module.render:
    const color = args.color || 'var(--accent-color)';
    const activeIndex = parseInt(args.active_index, 10) || 0;
    const cardBg = (args.cardbg || '#ffffff').trim() || '#ffffff';
    const gap = (args.gap || '2rem').trim() || '2rem';
    const shapeKey = String(args.markershape || 'pill').toLowerCase();
    const shape = ['pill', 'rounded', 'square'].includes(shapeKey) ? shapeKey : 'pill';
    const connector = String(args.connector) !== 'false';

    const indexesArr = Array.isArray(args.indexes) ? args.indexes : [];

    const wrapCls = `mdp-mod-timeline mdp-tl-mk-${shape}` + (connector ? '' : ' mdp-tl-noline');
    let html = `\n\n<div class="${wrapCls}" style="--timeline-color: ${color}; --timeline-card: ${cardBg}; --timeline-gap: ${gap};">\n`;

    sections.forEach((section, index) => {
       const contentStr = section.trim();
       if (!contentStr) return;

       const currentNum = index + 1;
       const label = indexesArr[index] !== undefined && indexesArr[index] !== '' ? indexesArr[index] : currentNum;
       const isActive = currentNum === activeIndex;
       const activeClass = isActive ? ' active' : '';

       html += `
<div class="mdp-timeline-item${activeClass}">
  <div class="mdp-timeline-marker${activeClass}">${label}</div>
  <div class="mdp-timeline-content${activeClass}">

${contentStr}

  </div>
</div>
`;
    });

    html += `</div>\n\n`;
    return html;
